// Common columns
const timestamps = {
  created: timestamp().defaultNow().notNull(),
  updated: timestamp().defaultNow().notNull(),
}
const timestampsDeleted = {
  ...timestamps,
  deleted: timestamp(),
}

// Team package permissions
export const permissionEnum = pgEnum('permissions', ['r', 'w'])
// Time slices for downloads
export const timesliceEnum = pgEnum('timeslices', ['d', 'm', 'y', 't'])
// Event methods
export const methodEnum = pgEnum('methods', ['get', 'post', 'put', 'delete'])
// Paddle subscription statuses
export const subscriptionStatusEnum = pgEnum('subscription_status', [
  'trialing',
  'active',
  'past_due',
  'paused',
  'canceled',
])

// Binary columns
// https://github.com/drizzle-team/drizzle-orm/issues/298#issuecomment-3223856537
export const bytea = customType<{ data: Buffer, notNull: false, default: false }>({
  dataType(): string {
    return 'bytea'
  },
  toDriver(value: unknown): SQL<unknown> {
    if (!(value instanceof Buffer)) {
      throw new TypeError(`Value of type ${typeof value} is not a Buffer`)
    }

    return sql`decode(${value.toString('hex')}, 'hex')`
  },
  fromDriver(value: unknown): Buffer<ArrayBufferLike> {
    if (value instanceof Buffer) {
      return value
    }

    if (typeof value === 'string') {
      const HEX_ESCAPE_REGEX = /\\x/g
      return Buffer.from(value.replace(HEX_ESCAPE_REGEX, ''), 'hex')
    }

    throw new Error(`Cannot convert value of type ${typeof value} to a Buffer`)
  },
})

// Full text search
export const tsVector = customType<{ data: string, notNull: false, default: false }>({
  dataType() {
    return 'tsvector'
  },
  fromDriver(value: unknown): string {
    return value as string
  },
})

