/**
 * Readmes
 */
export const readmes = pgTable(
  'readmes',
  {
    id: serial().unique(),
    org_id: integer().references(() => orgs.id),
    name: text().notNull(),
    version: text().notNull(),
    markdown: text().notNull(),
    search_english: tsVector().generatedAlwaysAs(
      (): SQL => sql`to_tsvector('english', coalesce(${readmes.markdown}, ''))`,
    ),
    search_german: tsVector().generatedAlwaysAs(
      (): SQL => sql`to_tsvector('german', coalesce(${readmes.markdown}, ''))`,
    ),
    ...timestampsDeleted,
  },
  t => [
    primaryKey({ columns: [t.org_id, t.name, t.version] }),
    index('readme_search_english').using('gin', t.search_english),
    index('readme_search_german').using('gin', t.search_german),
  ],
)

/**
 * Metadata
 */
export const metadata = pgTable(
  'metadata',
  {
    id: serial().unique(),
    org_id: integer().references(() => orgs.id),
    name: text().notNull(),
    version: text().notNull(),
    description: text(),
    keywords: text(),
    search_english: tsVector().generatedAlwaysAs(
      (): SQL => sql`
      setweight(to_tsvector('english', coalesce(${metadata.name}, '')), 'A') || ' ' ||
      setweight(to_tsvector('english', coalesce(${metadata.version}, '')), 'B') || ' ' ||
      setweight(to_tsvector('english', coalesce(${metadata.description}, '')), 'C') || ' ' ||
      setweight(to_tsvector('english', coalesce(${metadata.keywords}, '')), 'D')`,
    ),
    search_german: tsVector().generatedAlwaysAs(
      (): SQL => sql`
      setweight(to_tsvector('german', coalesce(${metadata.name}, '')), 'A') || ' ' ||
      setweight(to_tsvector('german', coalesce(${metadata.version}, '')), 'B') || ' ' ||
      setweight(to_tsvector('german', coalesce(${metadata.description}, '')), 'C') || ' ' ||
      setweight(to_tsvector('german', coalesce(${metadata.keywords}, '')), 'D')`,
    ),
    ...timestampsDeleted,
  },
  t => [
    primaryKey({ columns: [t.org_id, t.name, t.version] }),
    index('metadata_search_english').using('gin', t.search_english),
    index('metadata_search_german').using('gin', t.search_german),
  ],
)

