import buildDebug from 'debug'
import { and, eq, isNull, or, sql } from 'drizzle-orm'

import { errorUtils } from '@verdaccio/core'
import { Logger } from '@verdaccio/types'

import { type Database } from '../db'
import { gtadir } from '../db/schema'
import { TenantService } from './tenant'

const debug = buildDebug('verdaccio:plugin:pro:db')

type NameVersion = {
  name: string
  version: string
}

export class GlobalTadirService {
  private db: Database
  private logger: Logger
  private tenant: TenantService

  public constructor(database: Database, logger: Logger) {
    this.db = database
    this.logger = logger
    this.tenant = new TenantService(database, logger)
  }

  public async exists(tadir: string[]): Promise<boolean> {
    debug('check if GTADIR entries exist')
    if (tadir.length === 0) {
      return false
    }

    const conditions = tadir.map((record) => {
      const [object, object_name] = record.split(',')
      return and(
        eq(gtadir.pgmid, 'R3TR'),
        eq(gtadir.object, object),
        eq(gtadir.object_name, object_name),
        isNull(gtadir.deleted),
      )
    })

    const existing = await this.db
      .select({ id: gtadir.id })
      .from(gtadir)
      .where(or(...conditions))
      .limit(1)

    debug('Existing GTADIR entries: %o', existing.length)
    return existing.length > 0
  }

  public async check(tadir: string[]): Promise<NameVersion[]> {
    debug('check GTADIR entries and return names and versions')
    if (tadir.length === 0) {
      return []
    }

    const conditions = tadir.map((record) => {
      const [object, object_name] = record.split(',')
      return and(
        eq(gtadir.pgmid, 'R3TR'),
        eq(gtadir.object, object),
        eq(gtadir.object_name, object_name),
        isNull(gtadir.deleted),
      )
    })

    const results = await this.db
      .selectDistinct({ name: gtadir.name, version: gtadir.version })
      .from(gtadir)
      .where(or(...conditions))

    debug('Found GTADIR entries: %o', results.length)
    return results
  }

  public async add(name: string, version: string, tadir: string[]): Promise<void> {
    debug('add GTADIR %o %o, records %o', name, version, tadir.length)

    if (await this.exists(tadir)) {
      throw errorUtils.getInternalError(`Objects already exist in GTADIR database`)
    }

    const org_id = await this.tenant.get(name)

    const tadirData = tadir.map((record) => {
      const [object, object_name] = record.split(',')
      return {
        pgmid: 'R3TR',
        object,
        object_name,
        org_id,
        name,
        version,
        created: new Date(),
        updated: new Date(),
        deleted: null,
      }
    })

    try {
      await this.db
        .insert(gtadir)
        .values(tadirData)

      debug('GTADIR %o has been added', name)
    }
    catch (error) {
      debug('upsert error: %o', error)
      throw errorUtils.getInternalError(`Error adding GTADIR: ${error}`)
    }
  };

  public async remove(name: string, version: string): Promise<void> {
    debug('remove GTADIR %o, version %o', name, version)
    const org_id = await this.tenant.get(name)

    try {
      await this.db
        .delete(gtadir)
        .where(and(eq(gtadir.org_id, org_id), eq(gtadir.name, name), eq(gtadir.version, version)))

      debug('GTADIR %o, version %o has been removed', name, version)
    }
    catch (error) {
      debug('delete error: %o', error)
      throw errorUtils.getInternalError(`Error deleting GTADIR: ${error}`)
    }
  };

  public async get(name: string, version?: string): Promise<string[]> {
    debug('get object list of package')
    const org_id = await this.tenant.get(name)

    const objects = await this.db
      .select({ pgmid: gtadir.pgmid, object: gtadir.object, object_name: gtadir.object_name })
      .from(gtadir)
      .where(and(
        eq(gtadir.org_id, org_id),
        eq(gtadir.name, name),
        version ? eq(gtadir.version, version) : undefined,
        isNull(gtadir.deleted),
      ))
      .orderBy(gtadir.name)

    debug('list of %o objects has been fetched', objects ? objects.length : 0)
    return objects.map(row => `${row.pgmid},${row.object},${row.object_name}`)
  };

  public async clean(): Promise<void> {
    debug('clean all GTADIR')

    await this.db
      .execute(sql`TRUNCATE TABLE gtadir`)
  };
}
