import { DefaultLogger, LogWriter } from 'drizzle-orm/logger'

import { Logger } from '@verdaccio/types'

import { BLUE, CYAN, GREEN, MAGENTA, RED, RESET, YELLOW } from './tools/colors'

class VerdaccioLogWriter implements LogWriter {
  constructor(private logger: Logger) { }

  write(message: string) {
    let msg = message.replace(/^Query:\s*/i, '')
    if (msg.length > 500) {
      msg = msg.substring(0, 497) + '...'
    }

    // redact sensitive data
    if (msg.includes('users') || msg.includes('user_secrets') || msg.includes('secrets') || msg.includes('tokens')) {
      msg = msg.split(' ')[0] + '<Classified>'
    }

    const coloredMsg = msg.replace(/^(\w+)/i, (_, word) => {
      const lword = word.toLowerCase()
      const colors = {
        select: CYAN,
        insert: BLUE,
        update: GREEN,
        delete: MAGENTA,
        truncate: RED,
      }
      const color = colors[lword as keyof typeof colors]
      return `${color || YELLOW}${word}${RESET}`
    })

    this.logger.info(`SQL: ${coloredMsg}`)
  }
}

export const loggerFactory = (logger?: Logger): DefaultLogger | undefined => {
  return logger ? new DefaultLogger({ writer: new VerdaccioLogWriter(logger!) }) : undefined
}
